package com.promonts.dto;import com.promonts.domain.assignment.Assignment;import lombok.*;import java.time.LocalDateTime;@Data @NoArgsConstructor @AllArgsConstructor @Builder public class AssignmentResponse{private Long id;private String title;private String description;private LocalDateTime dueDate;private CourseInfo course;private LocalDateTime createdAt;@Data @AllArgsConstructor public static class CourseInfo{private Long id;private String name;private String code;}public static AssignmentResponse from(Assignment assignment){CourseInfo courseInfo=new CourseInfo(assignment.getCourse().getId(),assignment.getCourse().getName(),assignment.getCourse().getCode());return AssignmentResponse.builder().id(assignment.getId()).title(assignment.getTitle()).description(assignment.getDescription()).dueDate(assignment.getDueDate()).course(courseInfo).createdAt(assignment.getCreatedAt()).build();}}
